<template>
    <div class="table-responsive table-fix-header">
        <input type="hidden" id="hdnCreditAmountBalance" :value="creditAmountBalance" />
        <table v-if="lineItems && lineItems.length > 0" id="tblInvoiceItem"
            class="table table-bordered dt-responsive nowrap mt-0">
            <thead class="thead-bg">
                <tr>
                    <th style="text-align: center;" width="3%" class="alwaysshow" id="nonresize">
                        <div class="form-check form-check-inline">
                            <div class="custom-control custom-checkbox custom-control-inline">
                                <input type="checkbox" class="chkItems custom-control-input" id="chkAll" name="checkbox"
                                    data-change-id="no" :data-selectallinvoice="selectAllInvoice"
                                    @change="onSelectAllChange" />
                                <label class="custom-control-label" for="chkAll">
                                </label>
                            </div>
                        </div>
                    </th>
                    <th v-for="(header, index) in headers" :key="index" :width="getColumnWidth() + '%'"
                        :class="getHeaderClass(index)" :data-datatype="header.dataType"
                        :data-colname="'Col' + (index + 1)">
                        <span @click="onColumnSort('Col' + (index + 1))" class="sort" :id="'Col' + (index + 1)">
                            {{ header.displayName || header.columnName || 'Column ' + (index + 1) }}
                        </span>
                        <div title="Drag to resize column" class="resize-handle">
                            <em class="fa fa-ellipsis-v"></em>
                        </div>
                    </th>
                    <th class="text-center alwaysshow" width="4%">
                        <span>{{ $t('USICDiscount') }}</span>
                    </th>
                    <th class="text-center alwaysshow" width="3%">
                        <span>{{ $t('Edit') }}</span>
                    </th>
                </tr>
            </thead>
            <tbody>
                <tr v-for="(item, rowIndex) in lineItems" :key="item.lineItemId || rowIndex" :class="getRowClass(item)"
                    :price="getCostValue(item)">
                    <td style="text-align: center;" class="alwaysshow" width="3%">
                        <div v-if="item.ticketType === 'F' || item.isManual === true"
                            class="form-check form-check-inline">
                            <div class="custom-control custom-checkbox custom-control-inline">
                                <input class="chkItems custom-control-input" type="checkbox" disabled="disabled"
                                    :id="'chkItem_' + item.lineItemId" :value="item.lineItemId" name="DeleteInputs" />
                                <label class="custom-control-label" :for="'chkItem_' + item.lineItemId">
                                </label>
                            </div>
                        </div>
                        <div v-else class="form-check form-check-inline">
                            <div class="custom-control custom-checkbox custom-control-inline">
                                <input class="chkItems custom-control-input" type="checkbox"
                                    :id="'chkItem_' + item.lineItemId" :value="item.lineItemId" name="DeleteInputs"
                                    v-model="item.selected" />
                                <label class="custom-control-label" :for="'chkItem_' + item.lineItemId">
                                </label>
                            </div>
                        </div>
                        <input type="hidden" :value="item.lineItemId" />
                    </td>
                    <td v-for="(header, colIndex) in headers" :key="colIndex" :width="getColumnWidth() + '%'"
                        :class="getCellClass(header, colIndex)" :data-colvalue="getColumnValue(item, colIndex)"
                        :data-datatype="header.dataType" :data-colname="header.columnName || header.displayName"
                        :title="getColumnValue(item, colIndex)">
                        <span v-if="colIndex === 0 && !getColumnValue(item, colIndex)" style="visibility:hidden;">
                            Do not delete this its mandatory
                        </span>
                        <!-- <span
                           
                            v-else-if="(header.columnName || header.displayName || '').toLowerCase().trim() === 'cost'">
                             {{ (getCostValue(item.col7) || 0).toFixed(2) }} 
                            {{ item.col7 }}
                        </span> -->

                        <span v-else>
                            {{ formatColumnValue(item, colIndex, header) }}
                        </span>
                    </td>
                    <td class="text-center alwaysshow single-action" width="4%">
                        <a v-if="item.discount > 0" :data-itemid="item.lineItemId" :data-cost="getCostValue(item)"
                            :title="$t('Edit')" class="aAddDiscount" @click="onAddDiscount(item)">
                            {{ formatDiscount(item.discount) }}
                        </a>
                        <a v-if="item.discount > 0" href="javascript:;" :title="$t('Delete')"
                            :data-itemid="item.lineItemId" class="aDeleteDiscount cross enable cursorpointer"
                            @click="onDeleteDiscount(item)">
                            <em class="fa fa-times text-danger"></em>
                        </a>
                        <a v-else href="javascript:;" :title="$t('Add')" :data-cost="getCostValue(item)"
                            :data-itemid="item.lineItemId" class="aAddDiscount add enable cursorpointer"
                            @click="onAddDiscount(item)">
                            <em class="fa fa-plus-circle text-primary"></em>
                        </a>
                        <a v-if="!item.discount || item.discount === 0" href="javascript:;" :title="$t('Delete')"
                            :data-itemid="item.lineItemId" class="aDeleteDiscount cross enable cursorpointer hidden">
                            <em class="fa fa-times text-danger"></em>
                        </a>
                    </td>
                    <td class="text-center alwaysshow single-action" width="3%">
                        <a :title="$t('Edit')" class="text-success ancedit enable" style="cursor:pointer;"
                            :data-tickettype="item.ticketType || item.TicketType"
                            :data-isticketmannual="(item.isManual === true || item.IsManual === true) ? 'M' : 'N'"
                            :lineId="item.lineItemId" :COLUMN_ID="item.tranNo || item.TranNo"
                            @click="onEditLineItem(item)">
                            <em class="fa fa-pencil"></em>
                        </a>
                    </td>
                </tr>
            </tbody>
        </table>
        <table v-else class="table table-bordered dt-responsive nowrap mt-0">
            <tr>
                <td class="text-danger text-center no-record">{{ $t('NoRecordfound') }}</td>
            </tr>
        </table>
        <input type="hidden" id="hdnSumNonVisibleInSummary" :value="notInSummaryCost" />
        <input type="hidden" id="hdnSubTotal" :value="subTotal" />
    </div>
</template>

<script>
export default {
    name: "LineItems",
    props: {
        lineItems: {
            type: Array,
            default: () => []
        },
        headers: {
            type: Array,
            default: () => []
        },
        subTotal: {
            type: Number,
            default: 0
        },
        creditAmountBalance: {
            type: Number,
            default: 0
        },
        notInSummaryCost: {
            type: Number,
            default: 0
        },
        selectAllInvoice: {
            type: String,
            default: ''
        },
        colCount: {
            type: Number,
            default: null
        }
    },
    computed: {
        columnCount() {
            // Match MVC logic: var ColumnCount = Model.Records.First().ColCount / 2;
            // However, we want to show ALL columns, so we return a number larger than any possible column index
            // This ensures no columns are hidden by the hideColumnLineItem class
            if (this.colCount !== null && this.colCount !== undefined) {
                // Return a number larger than headers.length to show all columns
                return this.headers ? this.headers.length + 100 : 100;
            }
            // Fallback: show all headers
            return this.headers ? this.headers.length + 100 : 100;
        },
        allHeaders() {
            // Ensure we return all headers
            return this.headers || [];
        }
    },
    watch: {
        headers: {
            handler() {
                this.$nextTick(() => {
                    this.initColumnResize();
                });
            },
            deep: true
        },
        lineItems: {
            handler() {
                this.$nextTick(() => {
                    this.initColumnResize();
                });
            },
            deep: true
        }
    },
    mounted() {
        this.$nextTick(() => {
            this.initColumnResize();
        });
    },
    methods: {
        getHeaderClass(index) {
            // Match MVC logic: if (i > ColumnCount) class="hideColumnLineItem"
            return index > this.columnCount ? 'hideColumnLineItem' : '';
        },
        getColumnWidth() {
            // Calculate column width similar to CSHTML: 90M / headersArray.Count()
            var headerCount = this.headers ? this.headers.length : 1;
            if (headerCount === 0) return 10;
            return Math.floor(90 / headerCount);
        },
        getRowClass(item) {
            // Similar to CSHTML row class logic - handle both camelCase and PascalCase
            var rowClass = '';
            var isManual = item.isManual === true || item.IsManual === true;
            var isNonVisible = item.isNonVisibleInSummary === true || item.IsNonVisibleInSummary === true;

            if (isManual) {
                rowClass = 'low-bar';
            }
            if (isNonVisible && !isManual) {
                rowClass = 'high-bar';
            }
            if (isManual && isNonVisible) {
                rowClass = 'critical-bar';
            }
            return rowClass;
        },
        getColumnValue(item, colIndex) {
            // Get value from col1, col2, etc. based on index - handle both camelCase and PascalCase
            var colName = 'col' + (colIndex + 1);
            var ColName = 'Col' + (colIndex + 1);
            return item[colName] || item[ColName] || '';
        },
        getCellClass(header, colIndex) {
            var cssClass = '';
            // Add txtUTotal class for cost column (col8, index 7)
            if (colIndex === 7) {
                cssClass += 'txtUTotal ';
            }
            // Add textalignright for numeric types
            if (header.dataType === 'D' || header.dataType === 'I' || header.dataType === 'Si') {
                cssClass += 'textalignright';
            }
            // Add hideColumnLineItem if beyond column count - match MVC logic
            // MVC uses: if (heardeCount > ColumnCount)
            // heardeCount starts at 0 and increments, so we check colIndex
            if (colIndex > this.columnCount) {
                cssClass += ' hideColumnLineItem';
            }
            return cssClass.trim();
        },
        formatColumnValue(item, colIndex, header) {

            var txtValue = this.getColumnValue(item, colIndex);
            if (!txtValue && txtValue !== 0) return '';

            var dataType = header.dataType || '';
            var format = header.format || 'N';

            // Match MVC logic: Check if column name is "cost" to use costValue
            var columnName = (header.columnName || header.displayName || '').toLowerCase().trim();
            var isCostColumn = columnName === 'cost';
            var costValue = 0;

            // Calculate costValue if this is the cost column (matching MVC logic)
            if (isCostColumn) {
                try {
                    var parsedCost = parseFloat(txtValue);
                    if (!isNaN(parsedCost)) {
                        costValue = parsedCost;
                    }
                } catch (e) {
                    console.warn('Error parsing cost:', e);
                }
            }

            // Format based on data type (matching CSHTML logic)
            if (dataType === 'DT' && txtValue) {
                // DateTime formatting
                try {
                    var date = new Date(txtValue);
                    if (!isNaN(date.getTime())) {
                        if (format && format !== 'N') {
                            // Use custom format if provided
                            return this.formatDate(date, format);
                        } else {
                            // Default: MM/dd/yyyy HH:mm (matching ToShortDateString() + " " + ToShortTimeString())
                            return this.formatDate(date, 'MM/dd/yyyy') + ' ' + this.formatTime(date);
                        }
                    }
                } catch (e) {
                    console.warn('Error formatting date:', e);
                }
            } else if (dataType === 'T' && txtValue) {
                // Time formatting

                if (typeof txtValue === 'string') {
                    // Match time like 11:59PM or 3:45AM
                    const timeMatch = txtValue.match(/(\d{1,2}:\d{2}\s?[AP]M)/i);
                    if (timeMatch) {
                        return timeMatch[1].replace(' ', '');
                    }
                }

                try {
                    var date = new Date(txtValue);
                    if (!isNaN(date.getTime())) {
                        if (format && format !== 'N') {
                            return this.formatDate(date, format);
                        } else {
                            return this.formatTime(date);
                        }
                    }
                } catch (e) {
                    console.warn('Error formatting time:', e);
                }
            } else if (dataType === 'D' && txtValue) {
                // Decimal formatting - match MVC: String.Format("{0:f2}", decimal.Parse(...))
                try {
                    var num = parseFloat(txtValue);
                    if (!isNaN(num)) {
                        return num.toFixed(2);
                    }
                } catch (e) {
                    console.warn('Error formatting decimal:', e);
                }
            }

            // Match MVC logic: if column name is "cost", display costValue instead of txtValue
            if (isCostColumn && costValue !== 0) {
                return costValue.toFixed(2);
            }

            return txtValue;
        },
        formatDate(date, format) {
            // Simple date formatting
            var month = (date.getMonth() + 1).toString().padStart(2, '0');
            var day = date.getDate().toString().padStart(2, '0');
            var year = date.getFullYear();

            if (format === 'MM/dd/yyyy') {
                return month + '/' + day + '/' + year;
            }
            // Add more format options as needed
            return month + '/' + day + '/' + year;
        },
        formatTime(date) {
            var hours = date.getHours();
            var minutes = date.getMinutes();
            var ampm = hours >= 12 ? 'PM' : 'AM';
            hours = hours % 12;
            hours = hours ? hours : 12;
            var minutesStr = minutes.toString().padStart(2, '0');
            return hours + ':' + minutesStr + ' ' + ampm;
        },
        getCostValue(item) {
            // Get cost value from col8 - handle both camelCase and PascalCase
            return parseFloat(item.col8 || item.Col8 || 0);
        },
        isNumericType(dataType) {
            return dataType === 'D' || dataType === 'I' || dataType === 'Si';
        },
        onSelectAllChange(event) {
            this.$emit('select-all-change', event.target.checked);
        },
        onColumnSort(colName) {
            this.$emit('column-sort', colName);
        },
        onAddDiscount(item) {
            this.$emit('add-discount', item);
        },
        onDeleteDiscount(item) {
            this.$emit('delete-discount', item);
        },
        onEditLineItem(item) {
            this.$emit('edit-line-item', item);
        },
        formatDiscount(discount) {
            if (!discount || discount === 0) return '';
            return parseFloat(discount).toFixed(2);
        },
        initColumnResize() {
            var vm = this;
            var table = document.getElementById('tblInvoiceItem');
            if (!table) return;

            var headers = table.querySelectorAll('thead th:not(#nonresize)');
            var isResizing = false;
            var currentHeader = null;
            var startX = 0;
            var startWidth = 0;

            headers.forEach(function (header) {
                var resizeHandle = header.querySelector('.resize-handle');
                if (!resizeHandle) return;

                resizeHandle.addEventListener('mousedown', function (e) {
                    e.preventDefault();
                    e.stopPropagation();
                    isResizing = true;
                    currentHeader = header;
                    startX = e.pageX;
                    startWidth = header.offsetWidth;

                    document.body.style.cursor = 'col-resize';
                    document.body.style.userSelect = 'none';

                    header.style.userSelect = 'none';
                });
            });

            document.addEventListener('mousemove', function (e) {
                if (!isResizing || !currentHeader) return;

                var diff = e.pageX - startX;
                var newWidth = startWidth + diff;

                // Minimum width constraint
                if (newWidth < 50) {
                    newWidth = 50;
                }

                currentHeader.style.width = newWidth + 'px';
                currentHeader.style.minWidth = newWidth + 'px';
                currentHeader.style.maxWidth = newWidth + 'px';
            });

            document.addEventListener('mouseup', function () {
                if (isResizing) {
                    isResizing = false;
                    currentHeader = null;
                    document.body.style.cursor = '';
                    document.body.style.userSelect = '';

                    if (currentHeader) {
                        currentHeader.style.userSelect = '';
                    }
                }
            });
        }
    }
}
</script>

<style scoped>
.textalignright {
    text-align: right;
}

.low-bar {
    background-color: #fff3cd;
}

.high-bar {
    background-color: #f8d7da;
}

.critical-bar {
    background-color: #d1ecf1;
}

.hideColumnLineItem {
    display: none;
}

.resize-handle {
    position: absolute;
    right: 0;
    top: 0;
    bottom: 0;
    width: 5px;
    cursor: col-resize;
    user-select: none;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: transparent;
    z-index: 10;
}

.resize-handle:hover {
    background-color: rgba(0, 123, 255, 0.1);
}

.resize-handle em {
    font-size: 12px;
    color: #6c757d;
    opacity: 0.5;
}

.resize-handle:hover em {
    opacity: 1;
    color: #007bff;
}

thead th {
    position: relative;
}
</style>
